-- MathToolsHub database-driven catalogue
-- Run in Supabase Dashboard > SQL Editor.
create table if not exists public.catalogue_items (
 id bigint generated by default as identity primary key,
 activity_id text unique not null check (char_length(activity_id) between 1 and 120),
 title text not null, description text not null default '', url text not null,
 section text not null check (section in ('primary','secondary')),
 icon text not null default '∑', sort_order integer not null default 0,
 active boolean not null default true, featured boolean not null default false,
 created_at timestamptz not null default now(), updated_at timestamptz not null default now()
);
alter table public.catalogue_items enable row level security;
drop policy if exists "Anyone reads active catalogue" on public.catalogue_items;
create policy "Anyone reads active catalogue" on public.catalogue_items for select to anon,authenticated using(active=true);
drop policy if exists "Admins manage catalogue" on public.catalogue_items;
create policy "Admins manage catalogue" on public.catalogue_items for all to authenticated
 using(exists(select 1 from public.profiles where id=(select auth.uid()) and role='admin'))
 with check(exists(select 1 from public.profiles where id=(select auth.uid()) and role='admin'));
grant select on public.catalogue_items to anon,authenticated;
grant insert,update,delete on public.catalogue_items to authenticated;
grant usage,select on sequence public.catalogue_items_id_seq to authenticated;
on conflict(activity_id) do update set title=excluded.title,description=excluded.description,url=excluded.url,section=excluded.section,icon=excluded.icon,sort_order=excluded.sort_order,updated_at=now();
